import { Component } from '@angular/core';

type TabId = 'overview' | 'details' | 'settings';

@Component({
  selector: 'app-root',
  standalone: true,
  template: `
    <main class="shell">
      <section class="card">
        <h1>Tabs / Multi-View Switcher</h1>

        <nav class="tabs" role="tablist" aria-label="Example tabs">
          <button
            id="tab-overview"
            class="tab"
            role="tab"
            [class.active]="isActive('overview')"
            [attr.aria-selected]="isActive('overview')"
            aria-controls="panel-overview"
            (click)="selectTab('overview')">Overview</button>
          <button
            id="tab-details"
            class="tab"
            role="tab"
            [class.active]="isActive('details')"
            [attr.aria-selected]="isActive('details')"
            aria-controls="panel-details"
            (click)="selectTab('details')">Details</button>
          <button
            id="tab-settings"
            class="tab"
            role="tab"
            [class.active]="isActive('settings')"
            [attr.aria-selected]="isActive('settings')"
            aria-controls="panel-settings"
            (click)="selectTab('settings')">Settings</button>
        </nav>

        @if (isActive('overview')) {
          <section id="panel-overview" class="panel" role="tabpanel" aria-labelledby="tab-overview">
            <h2>Overview</h2>
            <p>Show a short summary or welcome message here.</p>
          </section>
        }

        @if (isActive('details')) {
          <section id="panel-details" class="panel" role="tabpanel" aria-labelledby="tab-details">
            <h2>Details</h2>
            <p>Display more detailed information in this panel.</p>
          </section>
        }

        @if (isActive('settings')) {
          <section id="panel-settings" class="panel" role="tabpanel" aria-labelledby="tab-settings">
            <h2>Settings</h2>
            <p>Display account preferences in this panel.</p>
          </section>
        }
      </section>
    </main>
  `,
  styles: [
    `.shell{min-height:100vh;display:grid;place-items:center;background:#020617;color:#e5e7eb;padding:24px;}`,
    `.card{width:100%;max-width:560px;background:#020617;border-radius:16px;border:1px solid #1f2937;padding:20px 20px 24px;box-shadow:0 18px 45px rgba(15,23,42,0.8);display:grid;gap:16px;}`,
    `.card h1{margin:0 0 4px;font-size:20px;font-weight:700;}`,
    `.tabs{display:flex;gap:8px;padding:4px;background:#020617;border-radius:999px;border:1px solid #1f2937;}`,
    `.tab{flex:1;padding:8px 10px;border-radius:999px;border:none;background:transparent;color:#9ca3af;font-size:13px;font-weight:600;cursor:pointer;transition:background .15s, color .15s;}`,
    `.tab.active{background:#e5e7eb;color:#020617;}`,
    `.panel{margin-top:4px;border-radius:12px;border:1px solid #111827;background:radial-gradient(circle at top left,#111827,#020617);padding:14px 16px;display:grid;gap:4px;}`,
    `.panel h2{margin:0 0 4px;font-size:16px;font-weight:600;}`,
    `.panel p{margin:0;font-size:13px;color:#d1d5db;line-height:1.5;}`
  ]
})
export class AppComponent {
  activeTab: TabId = 'overview';

  isActive(tab: TabId): boolean {
    return this.activeTab === tab;
  }

  selectTab(tab: TabId): void {
    this.activeTab = tab;
  }
}
